async (page) => {
  // Walk toward Blacksmith area (199, 169) - click in that direction
  const walkClick = await page.evaluate(() => {
    const camera = window.game.camera;
    const zoom = 3, tileSize = 16;
    // Target tile: 199, 169
    return {
      screenX: Math.round((199 * tileSize - camera.x) * zoom),
      screenY: Math.round((169 * tileSize - camera.y) * zoom)
    };
  });

  await page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, { x: walkClick.screenX, y: walkClick.screenY });

  await page.waitForTimeout(4000);
  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });

  // Check for NPCs nearby
  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const npcs = gs.nearby_entities.filter(e => e.type === 1).map(e => ({
      name: e.name, x: e.x, y: e.y, distance: e.distance, quest_npc: e.quest_npc, has_achievement: e.has_achievement
    }));
    return JSON.stringify({ pos: gs.player_position, npcs, level: gs.player_stats.level });
  });
  return state;
}

async (page) => {
  // Move to open ground, away from rats
  await page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, { x: 800, y: 300 }); // Move to right side, open ground
  await page.waitForTimeout(2000);

  // Wait for passive regen - 30 seconds
  for (let i = 0; i < 20; i++) {
    await page.waitForTimeout(2000);
    const hp = await page.evaluate(() => {
      const gs = window.__latestGameState;
      return gs.player_stats.hp;
    });
    if (hp >= 85) break;
  }

  const finalHp = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return { hp: gs.player_stats.hp, max_hp: gs.player_stats.max_hp, pos: gs.player_position };
  });

  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  return JSON.stringify(finalHp);
}

