async (page) => {
  // Walk to Village Girl at (136, 146)
  const vgClick = await page.evaluate(() => {
    const camera = window.game.camera;
    const zoom = 3, tileSize = 16;
    return {
      screenX: Math.round((136 * tileSize - camera.x) * zoom),
      screenY: Math.round((146 * tileSize - camera.y) * zoom)
    };
  });

  await page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, { x: vgClick.screenX, y: vgClick.screenY });
  await page.waitForTimeout(5000);

  const pos = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const vg = gs.nearby_entities.find(e => e.name === 'Village Girl');
    const camera = window.game.camera;
    const zoom = 3, tileSize = 16;
    if (vg) return {
      pos: gs.player_position, dist: vg.distance,
      screenX: Math.round((vg.x * tileSize - camera.x) * zoom),
      screenY: Math.round((vg.y * tileSize - camera.y) * zoom)
    };
    return { pos: gs.player_position, dist: null };
  });

  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  return JSON.stringify(pos);
}

async (page) => {
  // Walk west toward Village Girl at (136, 146) in steps
  for (let step = 0; step < 8; step++) {
    // Click toward VG - compute intermediate point
    const click = await page.evaluate(() => {
      const camera = window.game.camera;
      const gs = window.__latestGameState;
      const zoom = 3, tileSize = 16;
      const player = gs.player_position;

      // Target: halfway to VG from current position
      const targetX = Math.max(136, player.x - 10);
      const targetY = Math.max(146, player.y - 3);

      return {
        screenX: Math.max(50, Math.round((targetX * tileSize - camera.x) * zoom)),
        screenY: Math.round((targetY * tileSize - camera.y) * zoom),
        targetX, targetY, playerX: player.x, playerY: player.y
      };
    });

    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
    }, { x: click.screenX, y: click.screenY });
    await page.waitForTimeout(2500);

    // Check if Village Girl is now in range
    const vg = await page.evaluate(() => {
      const gs = window.__latestGameState;
      const vg = gs.nearby_entities.find(e => e.name === 'Village Girl');
      return vg ? { dist: vg.distance, x: vg.x, y: vg.y, quest_npc: vg.quest_npc } : null;
    });
    if (vg && vg.dist <= 3) break;
  }

  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const vg = gs.nearby_entities.find(e => e.name === 'Village Girl');
    return JSON.stringify({ pos: gs.player_position, vg: vg ? { dist: vg.distance, x: vg.x, y: vg.y } : null, hp: gs.player_stats.hp });
  });
  return state;
}

async (page) => {
  // Walk to Forester at (216, 114) in steps
  for (let step = 0; step < 10; step++) {
    const click = await page.evaluate(() => {
      const camera = window.game.camera;
      const gs = window.__latestGameState;
      const zoom = 3, tileSize = 16;
      const player = gs.player_position;

      const targetX = Math.min(216, player.x + 8);
      const targetY = Math.max(114, player.y - 8);

      const sx = Math.min(1230, Math.max(50, Math.round((targetX * tileSize - camera.x) * zoom)));
      const sy = Math.min(680, Math.max(50, Math.round((targetY * tileSize - camera.y) * zoom)));

      return { screenX: sx, screenY: sy, targetX, targetY, playerX: player.x, playerY: player.y };
    });

    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
    }, { x: click.screenX, y: click.screenY });
    await page.waitForTimeout(2000);

    // Check if Forester is nearby
    const forester = await page.evaluate(() => {
      const gs = window.__latestGameState;
      const f = gs.nearby_entities.find(e => e.name === 'Forester');
      return f ? { dist: f.distance } : null;
    });
    if (forester && forester.dist <= 5) break;
  }

  // Click through Forester dialogue
  for (let i = 0; i < 8; i++) {
    const fPos = await page.evaluate(() => {
      const camera = window.game.camera;
      const zoom = 3, tileSize = 16;
      const f = window.__latestGameState.nearby_entities.find(e => e.name === 'Forester');
      if (!f) return null;
      return {
        screenX: Math.round((f.x * tileSize - camera.x) * zoom),
        screenY: Math.round((f.y * tileSize - camera.y) * zoom)
      };
    });
    if (!fPos) break;

    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
    }, { x: fPos.screenX, y: fPos.screenY });
    await page.waitForTimeout(1200);
  }

  // Click quest button
  await page.evaluate(() => {
    const btn = document.getElementById('quest-button');
    if (btn) btn.click();
  });
  await page.waitForTimeout(1000);

  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return JSON.stringify({
      quests: gs.quests.filter(q => q.started),
      hp: gs.player_stats.hp,
      level: gs.player_stats.level,
      pos: gs.player_position
    });
  });
  return state;
}

async (page) => {
