  for (let step = 0; step < 10; step++) {
    const click = await page.evaluate(() => {
      const camera = window.game.camera;
      const gs = window.__latestGameState;
      const zoom = 3, tileSize = 16;
      const player = gs.player_position;

      // Move right toward x=216
      const targetX = Math.min(216, player.x + 10);
      const targetY = 114; // Stay at y=114

      const sx = Math.min(1230, Math.max(50, Math.round((targetX * tileSize - camera.x) * zoom)));
      const sy = Math.min(680, Math.max(50, Math.round((targetY * tileSize - camera.y) * zoom)));

      // Check Forester distance
      const f = gs.nearby_entities.find(e => e.name === 'Forester');
      return { screenX: sx, screenY: sy, playerX: player.x, fDist: f ? f.distance : null };
