async (page) => {
  // Walk right - click right edge of canvas
  for (let step = 0; step < 8; step++) {
    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
    }, { x: 1200, y: 380 }); // Right edge, middle y
    await page.waitForTimeout(2000);

    const check = await page.evaluate(() => {
      const gs = window.__latestGameState;
      const camera = window.game.camera;
      const zoom = 3, tileSize = 16;
      const f = gs.nearby_entities.find(e => e.name === 'Forester');
      if (!f) return { dist: 999, pos: gs.player_position };
      return {
        dist: f.distance, pos: gs.player_position,
        screenX: Math.round((f.x * tileSize - camera.x) * zoom)
      };
    });

    if (check.screenX <= 1200 && check.screenX > 0) break; // On screen now
  }

  // Now click Forester directly
  for (let i = 0; i < 10; i++) {
    const fPos = await page.evaluate(() => {
      const camera = window.game.camera;
      const zoom = 3, tileSize = 16;
      const f = window.__latestGameState.nearby_entities.find(e => e.name === 'Forester');
      if (!f) return null;
      const sx = Math.round((f.x * tileSize - camera.x) * zoom);
      const sy = Math.round((f.y * tileSize - camera.y) * zoom);
      return { screenX: Math.min(1200, Math.max(80, sx)), screenY: Math.min(660, Math.max(60, sy)), dist: f.distance };
    });
    if (!fPos) break;
    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
    }, { x: fPos.screenX, y: fPos.screenY });
    await page.waitForTimeout(1200);
  }

  await page.evaluate(() => { const btn = document.getElementById('quest-button'); if (btn) btn.click(); });
  await page.waitForTimeout(1000);
  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });

  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return JSON.stringify({
      quests: gs.quests.filter(q => q.started).map(q => q.name),
      pos: gs.player_position
    });
  });
  return state;
}

