async (page) => {
  // Walk to Village Girl at (136, 146) in steps
  for (let step = 0; step < 8; step++) {
    const click = await page.evaluate(() => {
      const camera = window.game.camera;
      const gs = window.__latestGameState;
      const zoom = 3, tileSize = 16;
      const player = gs.player_position;
      const vg = gs.nearby_entities.find(e => e.name === 'Village Girl');

      if (vg && vg.distance <= 2) return { done: true };

      const targetX = vg ? vg.x : 136;
      const targetY = vg ? vg.y : 146;

      // Move toward VG
      const dx = targetX - player.x;
      const dy = targetY - player.y;
      const stepX = player.x + Math.sign(dx) * Math.min(8, Math.abs(dx));
      const stepY = player.y + Math.sign(dy) * Math.min(8, Math.abs(dy));

      const sx = Math.min(1200, Math.max(80, Math.round((stepX * tileSize - camera.x) * zoom)));
      const sy = Math.min(660, Math.max(60, Math.round((stepY * tileSize - camera.y) * zoom)));
      return { screenX: sx, screenY: sy, done: false };
    });

    if (click.done) break;

    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
    }, { x: click.screenX, y: click.screenY });
    await page.waitForTimeout(2500);
  }

  // Click Village Girl for updated dialogue
  for (let i = 0; i < 6; i++) {
    const vgPos = await page.evaluate(() => {
      const camera = window.game.camera;
      const zoom = 3, tileSize = 16;
      const vg = window.__latestGameState.nearby_entities.find(e => e.name === 'Village Girl');
      if (!vg) return null;
      return {
        screenX: Math.min(1200, Math.max(80, Math.round((vg.x * tileSize - camera.x) * zoom))),
        screenY: Math.min(660, Math.max(60, Math.round((vg.y * tileSize - camera.y) * zoom)))
      };
    });
    if (!vgPos) break;

    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
    }, { x: vgPos.screenX, y: vgPos.screenY });
    await page.waitForTimeout(1200);
    await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  }

  // Try quest button
  await page.evaluate(() => { const btn = document.getElementById('quest-button'); if (btn) btn.click(); });
  await page.waitForTimeout(1000);

  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return JSON.stringify({
      scavengerStage: gs.quests.find(q => q.key === 'scavenger')?.stage,
      inventory: gs.inventory.map(i => i.name),
      pos: gs.player_position
    });
  });
  return state;
}

async (page) => {
  // Investigate quest details to understand what each stage requires
  const result = await page.evaluate(() => {
    try {
      // Try to access quest info from the game
      const questMenu = window.game?.menu?.quests;
      const quests = window.game?.quests;

      // Look for quest data structures
      const questKeys = quests ? Object.keys(quests) : [];

      // Try to get stage info for active quests
      let questDetails = {};

      // Check quest objects directly
      if (quests) {
        for (const key of questKeys.slice(0, 5)) {
          const q = quests[key];
          questDetails[key] = {
            name: q?.name,
            stage: q?.stage,
            stageCount: q?.stageCount,
            started: q?.started,
            data: q?.data ? JSON.stringify(q.data).slice(0, 200) : 'no data'
          };
        }
      }

      return JSON.stringify({ questKeys: questKeys.slice(0, 10), questDetails });
    } catch(e) {
      return 'Error: ' + e.message;
    }
  });
  return result;
}

async (page) => {
  // Run to safety - click center of Mudwich village to run away from mobs
  const camera = await page.evaluate(() => ({x: window.game?.camera?.x, y: window.game?.camera?.y}));
  const zoom = 3, tileSize = 16;

  // Walk east toward village proper (Blacksmith area)
  const targetX = 199, targetY = 169;
  const screenX = Math.round((targetX * tileSize - camera.x) * zoom);
  const screenY = Math.round((targetY * tileSize - camera.y) * zoom);
  const cx = Math.max(80, Math.min(1200, screenX));
  const cy = Math.max(60, Math.min(660, screenY));

  await page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, { x: cx, y: cy });

  await page.waitForTimeout(4000);

  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const pos = gs?.player_position;
    const hp = gs?.player_stats?.hp;
    const max_hp = gs?.player_stats?.max_hp;
    const entities = (gs?.nearby_entities || []).filter(e => e.type === 3).slice(0,5).map(e => `${e.name}(d${Math.round(e.distance)})`);
    return { hp, max_hp, pos, mobs: entities };
  });

  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  return JSON.stringify(state);
}

