async (page) => {
  // Walk south to find more trees, then chop them
  const clickAt = async (x, y, wait=2000) => {
    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
    }, { x, y });
    await page.waitForTimeout(wait);
  };

  // Move south toward more trees
  await clickAt(640, 500);
  await clickAt(640, 550);

  // Find all trees within range
  const treeList = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const camera = window.game?.camera;
    const zoom = 3, tileSize = 16;
    return (gs?.nearby_entities || []).filter(e => e.type === 10).slice(0, 10).map(e => ({
      sx: Math.round((e.x * tileSize - camera.x) * zoom),
      sy: Math.round((e.y * tileSize - camera.y) * zoom),
      x: e.x, y: e.y, d: Math.round(e.distance)
    }));
  });

  let logCount = 6;
  // Click each different tree
  for (const tree of treeList) {
    if (logCount >= 10) break;
    const cx = Math.max(80, Math.min(1200, tree.sx));
    const cy = Math.max(80, Math.min(620, tree.sy));
    await clickAt(cx, cy, 3500);

    logCount = await page.evaluate(() => {
      return (window.__latestGameState?.inventory || []).filter(i => i.name === 'Logs').length;
    });
  }

  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return {
      pos: gs?.player_position,
      inv: (gs?.inventory || []).map(i => `${i.name}(slot${i.slot})`),
      logCount: (gs?.inventory || []).filter(i => i.name === 'Logs').length
    };
  });
  return JSON.stringify(state);
}

