async (page) => {
  const getState = () => page.evaluate(() => {
    const gs = window.__latestGameState;
    const cam = window.game?.camera;
    const ts = 16, zoom = 3;
    const mobs = (gs.nearby_entities || []).filter(e => e.type === 3 && e.distance <= 10).map(e => ({
      name: e.name, tx: e.x, ty: e.y, dist: e.distance, hp: e.hp,
      sx: Math.round((e.x * ts - cam.x) * zoom), sy: Math.round((e.y * ts - cam.y) * zoom)
    }));
    const skills = window.game?.player?.skills;
    return {
      pos: gs.player_position, hp: gs.player_stats?.hp,
      level: gs.player_stats?.level, mobs,
      str: skills?.[3]?.experience, def: skills?.[6]?.experience, hpSkill: skills?.[7]?.experience,
      target: gs.current_target?.name
    };
  });

  const click = async (x, y, wait=4000) => {
    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
    }, {x, y});
    await page.waitForTimeout(wait);
  };

  // Kill 5 rats in a row
  let kills = 0;
  for (let attempt = 0; attempt < 15 && kills < 5; attempt++) {
    const s = await getState();
    if (s.mobs.length > 0) {
      const rat = s.mobs[0];
      await click(rat.sx, rat.sy, 5000);
      // Wait for kill
      await page.waitForTimeout(4000);
      const s2 = await getState();
      if (s2.str > (s?.str || 0) || s2.def > (s?.def || 0)) {
        kills++;
      }
    } else {
      // Walk around to find mobs
      await click(600 + Math.random() * 200, 400 + Math.random() * 100, 2000);
    }
  }

  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  const final = await getState();
  return JSON.stringify({ kills, pos: final.pos, hp: final.hp, str: final.str, def: final.def, hp_skill: final.hpSkill });
}

