          const name = e.name.toLowerCase();
          // Look for hammer, chest, item, treasure, or unusual objects near beach area (y=175-210, x=185-215)
          const isNearBeach = e.gridY > 175 && e.gridY < 215 && e.gridX > 175 && e.gridX < 215;
          if (isNearBeach || name.includes('hammer') || name.includes('chest') || name.includes('treasure') || name.includes('anvil')) {
            found.push({ 
              id, name: e.name, type: e.type, x: e.gridX, y: e.gridY,
              sx: Math.round((e.gridX * ts - cam.x) * zoom),
              sy: Math.round((e.gridY * ts - cam.y) * zoom)
            });
          }
        }
      }
    }
    const gs = window.__latestGameState;
    return JSON.stringify({ pos: gs.player_position, found: found.slice(0, 30) });
  });
  return fullScan;
}

