    const npcs = (gs?.nearby_entities || []).filter(e => e.type === 1 && e.distance <= 10).map(e => ({
      name: e.name, dist: e.distance, quest_npc: e.quest_npc
    }));
    return { pos: gs?.player_position, hp: gs?.player_stats?.hp, level: gs?.player_stats?.level, mobs, npcs };
  });

  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  return JSON.stringify(info);
}

