async (page) => {
  // Rapid escape - keep clicking away
  for (let i = 0; i < 5; i++) {
    await page.evaluate(() => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: 100, clientY: 100, bubbles: true }));
    });
    await page.waitForTimeout(1000);
    const hp = await page.evaluate(() => window.__latestGameState?.player_stats?.hp);
    if (!hp || hp === 0) break;
  }

  await page.waitForTimeout(5000);

  const info = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const mobs = (gs?.nearby_entities || []).filter(e => e.type === 3 && e.distance <= 5).map(e => e.name);
    return { pos: gs?.player_position, hp: gs?.player_stats?.hp, maxHp: gs?.player_stats?.max_hp, nearMobs: mobs };
  });

  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  return JSON.stringify(info);
}
